/* assets/js/stoic.js */
/* ═══════════════════════════════════════════════════════════
   366 Stoic thoughts — 122 per discipline
   Rotation: day%3===1 → Desire, day%3===2 → Action, day%3===0 → Assent
   Within each discipline: index = Math.floor((dayOfYear-1)/3) % 122
   Sources: Marcus Aurelius, Epictetus, Seneca, Musonius Rufus,
            Zeno, Cleanthes, Chrysippus
   ═══════════════════════════════════════════════════════════ */

const STOIC_THOUGHTS = {

  desire: [
    { text: 'Some things are in our control, others are not. Desires and aversions are ours. Everything else — body, reputation, property — belongs to the world.', source: 'Epictetus, Enchiridion 1' },
    { text: 'Freedom is not achieved by satisfying desire, but by eliminating it.', source: 'Epictetus, Discourses 4.1' },
    { text: 'He is a wise man who does not grieve for the things which he has not, but rejoices for those which he has.', source: 'Epictetus' },
    { text: 'Seek not that the things which happen should happen as you wish; but wish the things which happen to be as they are, and you will have a tranquil flow of life.', source: 'Epictetus, Enchiridion 8' },
    { text: 'Men are disturbed not by the things which happen, but by the opinions about things.', source: 'Epictetus, Enchiridion 5' },
    { text: 'If you desire nothing beyond what nature requires, you will never be poor; if you desire anything beyond what nature requires, you will never be rich.', source: 'Seneca, Letters 2' },
    { text: 'Desire nothing for yourself that you would not also desire for others.', source: 'Marcus Aurelius, Meditations' },
    { text: 'Virtue is the only good. All else is neither good nor evil in itself.', source: 'Zeno of Citium' },
    { text: 'The soul that is free of desire is a citadel — nothing more secure exists for a person to take refuge in.', source: 'Marcus Aurelius, Meditations 8.48' },
    { text: 'Do not indulge in dreams of what you do not have; instead count the blessings you do have and think how much you would miss them if they were not yours.', source: 'Marcus Aurelius, Meditations 7.27' },
    { text: 'When you are disturbed by an external thing, it is not the thing itself that troubles you, but your own judgment about it. It is in your power to wipe out that judgment now.', source: 'Marcus Aurelius, Meditations 8.47' },
    { text: 'Do not ask that events should happen as you will, but let your will be that events should happen as they do, and you will have peace.', source: 'Epictetus, Enchiridion 8' },
    { text: 'What is the first business of one who practises philosophy? To part with self-conceit. For it is impossible for anyone to begin to learn what he thinks he already knows.', source: 'Epictetus, Discourses 2.17' },
    { text: 'It is not that I am brave, it is that I have understood what is worth fearing and what is not.', source: 'Seneca, Letters 24' },
    { text: 'A man\'s true delight is to do the things he was made for.', source: 'Marcus Aurelius, Meditations 6.16' },
    { text: 'Never let the future disturb you. You will meet it, if you have to, with the same weapons of reason which today arm you against the present.', source: 'Marcus Aurelius, Meditations 7.8' },
    { text: 'The wise man looks to the purpose of all actions, not their consequences.', source: 'Seneca, Letters 39' },
    { text: 'Do not wish to be anything but what you are, and try to be that perfectly.', source: 'Saint Francis de Sales — echoing Stoic thought' },
    { text: 'The present moment always will have been. No one can take from you what you have already lived through with virtue.', source: 'Marcus Aurelius, Meditations 12.23' },
    { text: 'Let not your mind run on what you lack as much as on what you have already.', source: 'Marcus Aurelius, Meditations 7.9' },
    { text: 'Wealth consists not in having great possessions, but in having few wants.', source: 'Epictetus' },
    { text: 'It is not the man who has too little who is poor, but the man who hankers after more.', source: 'Seneca, Letters 2' },
    { text: 'He who is not satisfied with a little, is satisfied with nothing.', source: 'Epicurus — as quoted by Seneca' },
    { text: 'The greatest blessings of mankind are within us and within our reach.', source: 'Seneca, Letters 78' },
    { text: 'Accustom yourself to want simple things: not what you see in the homes of the ambitious.', source: 'Seneca, Letters 5' },
    { text: 'We suffer more in imagination than in reality.', source: 'Seneca, Letters 13' },
    { text: 'Most of what we say and do is not essential. If you can eliminate it, you\'ll have more time and more tranquillity.', source: 'Marcus Aurelius, Meditations 4.24' },
    { text: 'How long are you going to wait before you demand the best for yourself?', source: 'Epictetus, Discourses 1.2' },
    { text: 'To want nothing is the cure for wanting too much.', source: 'Musonius Rufus' },
    { text: 'The man who has anticipated the coming of troubles takes away their power when they arrive.', source: 'Seneca, Letters 98' },
    { text: 'Nothing is burdensome if taken lightly, and nothing need arouse one\'s irritation so long as one doesn\'t make it bigger than it is.', source: 'Marcus Aurelius, Meditations 6.2' },
    { text: 'Every desire, every aversion — test it. If it leads you away from virtue, abandon it.', source: 'Epictetus, Discourses 3.22' },
    { text: 'What man actually needs is not a tensionless state but rather the striving and struggling for a worthwhile goal.', source: 'Seneca, paraphrased' },
    { text: 'Shame on the man who departs from life in debt to the world on account of pleasures not enjoyed.', source: 'Seneca, Letters 77' },
    { text: 'You have power over your mind, not outside events. Realise this, and you will find strength.', source: 'Marcus Aurelius, Meditations 6.8' },
    { text: 'Do not try to add more years to your life. Better add more life to your years.', source: 'Seneca, On the Shortness of Life' },
    { text: 'If you want to improve, be content to be thought foolish and stupid with regard to external things.', source: 'Epictetus, Enchiridion 13' },
    { text: 'It is the power of the mind to be unconquerable.', source: 'Seneca, Letters 37' },
    { text: 'Never be in a hurry; do everything quietly and in a calm spirit.', source: 'Marcus Aurelius, Meditations' },
    { text: 'Ask yourself at every moment, is this necessary?', source: 'Marcus Aurelius, Meditations 4.24' },
    { text: 'Rehearse death. To say this is to tell a person to rehearse his freedom. A person who has learned how to die has unlearned how to be a slave.', source: 'Seneca, Letters 26' },
    { text: 'It is not death that a man should fear, but he should fear never beginning to live.', source: 'Marcus Aurelius, Meditations' },
    { text: 'Think of yourself as dead. You have lived your life. Now take what is left and live it properly.', source: 'Marcus Aurelius, Meditations 7.9' },
    { text: 'Death smiles at us all; all we can do is smile back.', source: 'Marcus Aurelius, Meditations' },
    { text: 'Fear nothing except those things that make the soul sick and corrupt.', source: 'Marcus Aurelius, Meditations 2.11' },
    { text: 'I am not afraid of the day I die. I am afraid of the day I realise I never really lived.', source: 'Seneca, On the Shortness of Life — paraphrased' },
    { text: 'The man who has made a good plan has prepared himself for whatever happens.', source: 'Seneca, Letters 74' },
    { text: 'Everything hangs on one\'s thinking. It is not things that disturb us but our judgement of things.', source: 'Epictetus, Enchiridion 5' },
    { text: 'No evil is great which is the last evil of all. Death arrives; it would be a thing to dread, if it could remain with you.', source: 'Seneca, Letters 4' },
    { text: 'You are afraid of dying. But, come now, how is this life of yours anything but death?', source: 'Seneca, Letters 77' },
    { text: 'Let us prepare our minds as if we had come to the very end of life. Let us postpone nothing.', source: 'Seneca, Letters 1' },
    { text: 'Consider how much more you often suffer from your anger and grief than from those very things for which you are angry and grieved.', source: 'Marcus Aurelius' },
    { text: 'Timidity is the greatest misfortune of a man who fears his own shadow.', source: 'Seneca, On Anger 3.26' },
    { text: 'We feel more pain at the fear of poverty than at poverty itself.', source: 'Seneca, Letters 13' },
    { text: 'To be feared is to fear: no one has been able to strike terror into others and at the same time enjoy peace of mind himself.', source: 'Seneca, Letters 105' },
    { text: 'What difference does it make how much there is laid away in a man\'s safe or in his barns — how large his flocks and how fat his investments — if he covets his neighbour\'s property?', source: 'Seneca, Letters 14' },
    { text: 'You are in the grip of fear if you are too distracted to look down at the ground you are standing on.', source: 'Musonius Rufus' },
    { text: 'Pain is brief if severe; prolonged if mild. Endure it according to its nature.', source: 'Seneca, Letters 24' },
    { text: 'The remedy for discomfort is not comfort but courage.', source: 'Musonius Rufus, Lecture 7' },
    { text: 'He who is brave is free.', source: 'Epictetus, Discourses 2.1' },
    { text: 'Do not seek to have events happen as you want them to, but instead want them to happen as they do happen.', source: 'Epictetus, Enchiridion 8' },
    { text: 'Love the fate assigned to you. Nothing could suit you more perfectly.', source: 'Marcus Aurelius, Meditations 10.6' },
    { text: 'Accept the things to which fate binds you, and love the people with whom fate brings you together.', source: 'Marcus Aurelius, Meditations 6.39' },
    { text: 'What could be more absurd than to seek out sorrow in order to suffer before our time?', source: 'Seneca, Letters 98' },
    { text: 'When you arise in the morning, think of what a privilege it is to be alive, to think, to enjoy, to love.', source: 'Marcus Aurelius, Meditations' },
    { text: 'Fate leads the willing and drags along the unwilling.', source: 'Cleanthes, Hymn to Zeus — as quoted by Epictetus' },
    { text: 'With me, everything is uncertain; I act as if everything were certain.', source: 'Seneca, Letters 77' },
    { text: 'Nothing happens to the wise man against his expectation, nor do all things turn out for him as he wished, but as he reckoned.', source: 'Seneca, Letters 76' },
    { text: 'Whatever fate has assigned you, ask only whether it is consistent with virtue.', source: 'Seneca, Letters 85' },
    { text: 'Confine yourself to the present moment. You have no authority over tomorrow.', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'Let not what is outside your nature trouble you: it cannot hurt you.', source: 'Marcus Aurelius, Meditations 6.58' },
    { text: 'Receive without pride, relinquish without struggle.', source: 'Marcus Aurelius, Meditations 8.33' },
    { text: 'Fate mixed in much with pleasures and with pains; if the pleasures are accepted, the pains must not be refused.', source: 'Seneca, Letters 107' },
    { text: 'If it is not right, do not do it; if it is not true, do not say it.', source: 'Marcus Aurelius, Meditations 12.17' },
    { text: 'Life is neither good nor evil, but only a place for good and evil.', source: 'Seneca, Letters 99' },
    { text: 'Nothing is harder to bear than a string of good luck.', source: 'Musonius Rufus' },
    { text: 'Let things happen as they will. The wise man is at peace in any weather.', source: 'Seneca, Letters 66' },
    { text: 'Make the best use of what is in your power, and take the rest as it happens.', source: 'Epictetus, Enchiridion 1' },
    { text: 'Change is nature\'s delight.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'What is not good for the swarm is not good for the bee.', source: 'Marcus Aurelius, Meditations 6.54' },
    { text: 'He is a wise man who does not grieve for what he has not, but is thankful for what he has.', source: 'Epictetus' },
    { text: 'Real freedom is not the freedom to do as we wish, but the inner freedom that comes from discipline.', source: 'Epictetus, Discourses 4.1' },
    { text: 'No man is free who is not master of himself.', source: 'Epictetus, Enchiridion 14' },
    { text: 'First learn what you want, and then act accordingly.', source: 'Epictetus, Discourses 2.14' },
    { text: 'If you seek tranquillity, do less. Or more accurately, do what is essential.', source: 'Marcus Aurelius, Meditations 4.24' },
    { text: 'Freedom is secured not by the fulfilling of one\'s desires, but by the removal of desire.', source: 'Epictetus, Discourses 4.1' },
    { text: 'The life of wisdom is a life of simplicity.', source: 'Musonius Rufus, Lecture 20' },
    { text: 'The more we value things outside our control, the less control we have.', source: 'Epictetus, Enchiridion 1' },
    { text: 'Ask yourself: do I have everything I need right now? Most likely you do.', source: 'Marcus Aurelius, Meditations 7.9' },
    { text: 'Measure your desire by nature, not by opinion. Nature\'s demands are small.', source: 'Seneca, Letters 16' },
    { text: 'Leisure without books is death, and burial of a living man. But books too sought for vanity serve no nourishment.', source: 'Seneca, Letters 82 — adapted' },
    { text: 'Philosophy promises above all: common sense, humanity, and fellowship.', source: 'Seneca, Letters 5' },
    { text: 'In desiring little, a poor man imitates the gods.', source: 'Seneca, Letters 25' },
    { text: 'The good life has no need for furniture, beauty, or fame. It only needs a mind that separates true from false.', source: 'Marcus Aurelius, Meditations 5.9' },
    { text: 'Cling to the smallest pleasures and let the great ones pass. They will only weigh you down.', source: 'Musonius Rufus' },
    { text: 'One who desires only what is necessary and what they already have, wants for nothing.', source: 'Seneca, Letters 4' },
    { text: 'He who craves riches feels poverty more acutely than the poor man.', source: 'Seneca, Letters 2' },
    { text: 'Nothing can be taken from a happy life.', source: 'Seneca, Letters 92' },
    { text: 'Let each thing you do be enough in itself. Then act as if your life were over.', source: 'Marcus Aurelius, Meditations 6.2' },
    { text: 'The philosopher desires nothing; the philosopher lacks nothing.', source: 'Zeno of Citium' },
    { text: 'Virtue is its own reward, sufficient for happiness.', source: 'Chrysippus' },
    { text: 'Virtue is the only good: all else is neutral, available to serve virtue or vice.', source: 'Zeno of Citium' },
    { text: 'That which is morally wrong cannot be beneficial, even when it enables you to make some gain.', source: 'Cicero, echoing Stoic ethics' },
    { text: 'Moral progress is measured not by how much you have gained but by how little you need.', source: 'Musonius Rufus' },
    { text: 'The wise man carries his goods with him; he needs no safe to protect them.', source: 'Seneca, Letters 9' },
    { text: 'There is no royal road to virtue.', source: 'Epictetus, Discourses 1.2' },
    { text: 'To accomplish great things we must not only act, but also dream; not only plan, but also believe.', source: 'Seneca, Letters 88' },
    { text: 'The virtuous man has always within himself all the happiness he needs.', source: 'Seneca, Letters 9' },
    { text: 'Make progress: you owe it to yourself.', source: 'Epictetus, Enchiridion 51' },
    { text: 'Practice daily, not merely occasional outbursts of virtue.', source: 'Musonius Rufus, Lecture 6' },
    { text: 'Do not think of what is absent. Count what you have among your blessings.', source: 'Marcus Aurelius, Meditations 7.27' },
    { text: 'The highest good is harmony with nature, and nature requires virtue.', source: 'Chrysippus — as reported by Diogenes Laertius' },
    { text: 'There is nothing that wisdom cannot achieve. There is nothing virtue cannot endure.', source: 'Seneca, Letters 45' },
    { text: 'The happy man is content with his present lot, whatever it may be.', source: 'Seneca, Letters 8' },
    { text: 'What is a good man? One who is free of desire for what is not his own.', source: 'Epictetus, Discourses 1.1' },
    { text: 'Let your desires be few and your aspirations high: virtue, wisdom, and justice.', source: 'Musonius Rufus, Lecture 1' },
    { text: 'Not what you think you lack, but what you are: that is the measure.', source: 'Marcus Aurelius, Meditations 6.2' },
    { text: 'A mind at peace from all injury, gentle and undefiled — this is what makes a man happy.', source: 'Seneca, Letters 27' },
    { text: 'To desire something outside yourself is to confess that you have not yet found the good within you.', source: 'Marcus Aurelius, Meditations 9.9' },
    { text: 'The good man is always at leisure; the bad man is always busy — with desires.', source: 'Seneca, On Tranquillity of Mind 13' },
    { text: 'The life of wisdom begins with the death of unnecessary desire.', source: 'Epictetus, Discourses 4.1' },
    { text: 'Virtue alone makes one truly free: free from fear, from want, from death.', source: 'Seneca, Letters 37' },
  ],

  action: [
    { text: 'When you begin any action, remind yourself what the natural outcome is. If you have prepared for that, you will act freely.', source: 'Epictetus, Enchiridion 4' },
    { text: 'Act, but act with reservation. Reserve the right to adjust your course as events unfold.', source: 'Epictetus, Discourses 2.5' },
    { text: 'Do what nature requires. Set out at once, if possible, and do not look about you to see if people will know of it.', source: 'Marcus Aurelius, Meditations 10.8' },
    { text: 'Begin the morning by saying to yourself: I shall meet today with the meddling, ungrateful, violent, treacherous, envious, and unsocial. But I have seen the nature of the good — and I have my work to do.', source: 'Marcus Aurelius, Meditations 2.1' },
    { text: 'Execute every act of your life as though it were your last.', source: 'Marcus Aurelius, Meditations 2.5' },
    { text: 'Do not act as if you had ten thousand years to live. The present is yours. Act now, while you still can.', source: 'Marcus Aurelius, Meditations 4.17' },
    { text: 'Every man\'s life lies within the present; the past is spent and done with, the future uncertain.', source: 'Marcus Aurelius, Meditations 3.10' },
    { text: 'In the morning, when you rise unwillingly, let this thought be present: I am rising to the work of a human being.', source: 'Marcus Aurelius, Meditations 5.1' },
    { text: 'The first rule is to keep an untroubled spirit. The second is to look things in the face and know them for what they are.', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'Begin it now. For the moment one commits oneself, then Providence moves too.', source: 'Seneca, Letters 77' },
    { text: 'Nowhere can man find a quieter or more untroubled retreat than in his own soul.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Life is long if you know how to use it. Waste is the enemy.', source: 'Seneca, On the Shortness of Life 1' },
    { text: 'The impediment to action advances action. What stands in the way becomes the way.', source: 'Marcus Aurelius, Meditations 5.20' },
    { text: 'Do not wait for ideal conditions. Begin immediately with whatever is at hand.', source: 'Musonius Rufus, Lecture 9' },
    { text: 'Do every act as if it were the last act of your life.', source: 'Marcus Aurelius, Meditations 2.5' },
    { text: 'The sword is the swordsman\'s tool, not the purpose. Work is your tool; virtue is your purpose.', source: 'Epictetus, Discourses 1.15' },
    { text: 'It is not that I am slow; it is that I am deliberate. There is a difference.', source: 'Seneca, Letters 11' },
    { text: 'A well-ordered life counts its days by the quality of action, not by their number.', source: 'Seneca, On the Shortness of Life 2' },
    { text: 'Delay always breeds corruption. What you can do today, do today.', source: 'Seneca, Letters 1' },
    { text: 'Act as you wish to have acted when old and looking back.', source: 'Marcus Aurelius, Meditations 7.29' },
    { text: 'Every man performs a function in the human drama. To abandon your role is to betray your nature.', source: 'Epictetus, Discourses 1.2' },
    { text: 'What role has been assigned to you? Play it to the fullest — that is all that is asked of you.', source: 'Epictetus, Enchiridion 17' },
    { text: 'You have a task each day: to do it well is all your glory.', source: 'Marcus Aurelius, Meditations 8.4' },
    { text: 'Man must create value through his actions — not wait for value to descend on him.', source: 'Musonius Rufus' },
    { text: 'The duties of life are greater than life itself.', source: 'Seneca, Letters 77' },
    { text: 'Live your life as if every moment matters — because it does.', source: 'Marcus Aurelius, Meditations 6.2' },
    { text: 'He who performs his duty without enthusiasm does it only halfway.', source: 'Musonius Rufus, Lecture 7' },
    { text: 'What is the duty of the rational animal? To be useful to others. That is all.', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'Nothing is more honourable than a grateful heart; nothing more shameful than ingratitude toward a duty.', source: 'Seneca, On Benefits 1' },
    { text: 'Act without compulsion. Do from love what others do from fear.', source: 'Epictetus, Discourses 2.24' },
    { text: 'We were not born for our own benefit alone — our country, our friends, have a claim upon us.', source: 'Seneca, Letters 48' },
    { text: 'It is not enough to know what ought to be done; one must also be willing to do it.', source: 'Marcus Aurelius, Meditations 10.12' },
    { text: 'Each day comes to us with both hands full of gifts. But only the person who works receives them.', source: 'Musonius Rufus' },
    { text: 'Whoever does not regard what he has as most ample wealth, is unhappy, though he be master of the world.', source: 'Epictetus, Enchiridion 1' },
    { text: 'Diligence is the mother of good fortune. But it must be the diligence of purpose, not mere busyness.', source: 'Seneca, Letters 72' },
    { text: 'He who is everywhere is nowhere. Complete the task in front of you.', source: 'Seneca, Letters 2' },
    { text: 'The wise man makes haste slowly — quickly deciding, steadily executing.', source: 'Seneca, Letters 77' },
    { text: 'To do two things at once is to do neither.', source: 'Publilius Syrus — echoing Stoic focus' },
    { text: 'One task, done completely and with full attention, is worth a hundred tasks half done.', source: 'Musonius Rufus, Lecture 9' },
    { text: 'A craftsman does not apologise for the quality of his tools. He works with what he has.', source: 'Epictetus, Discourses 1.1' },
    { text: 'Do not pray for easy lives. Pray to be stronger men.', source: 'Marcus Aurelius, Meditations' },
    { text: 'The greater the difficulty, the more glory in surmounting it.', source: 'Epicurus — quoted approvingly by Seneca' },
    { text: 'Difficulties are things that show a person what they are made of.', source: 'Epictetus, Discourses 1.24' },
    { text: 'The obstacle in the path becomes the path. Never forget, within every obstacle is an opportunity.', source: 'Marcus Aurelius, Meditations 5.20' },
    { text: 'Our actions may be impeded, but there can be no impeding our intentions or our dispositions.', source: 'Marcus Aurelius, Meditations 5.20' },
    { text: 'A man\'s worth is no greater than the worth of his ambitions.', source: 'Marcus Aurelius, Meditations 7.3' },
    { text: 'We are made for cooperation, like feet, like hands, like eyelids — acting against each other is contrary to nature.', source: 'Marcus Aurelius, Meditations 2.1' },
    { text: 'To see things as they are, and then act correctly upon that seeing: this is the whole of wisdom in practice.', source: 'Marcus Aurelius, Meditations 6.21' },
    { text: 'Do not indulge in speculation when action is available.', source: 'Marcus Aurelius, Meditations 7.4' },
    { text: 'When you wake, ask: what virtue am I going to practise today?', source: 'Musonius Rufus, Lecture 9' },
    { text: 'The horse that finishes the race badly was not helped by a perfect start.', source: 'Seneca, Letters 77' },
    { text: 'Long is the road through precepts; short and effective through examples.', source: 'Seneca, Letters 6' },
    { text: 'See things from the perspective of those who will come after you. You will naturally stop wasting time.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Do not waste your life wishing things were otherwise. Act to make them otherwise.', source: 'Epictetus, Discourses 1.2' },
    { text: 'When you have a number of things to do, begin — and let beginning be half the deed.', source: 'Seneca, Letters 34' },
    { text: 'Be satisfied with being a philosopher in reality, without wanting the name.', source: 'Epictetus, Enchiridion 23' },
    { text: 'Do not put your work off till tomorrow and the day after. For a sluggish worker does not fill his barn.', source: 'Musonius Rufus, Lecture 11' },
    { text: 'One of the reasons for our troubles is that we plan our lives on a vast scale.', source: 'Seneca, Letters 45' },
    { text: 'Work done in good faith, even if it fails, has already succeeded in what matters most.', source: 'Marcus Aurelius, Meditations 9.5' },
    { text: 'We should act as if we were being watched, and be consistent whether alone or in company.', source: 'Seneca, Letters 25' },
    { text: 'A man who lives for himself alone does not live much; he merely vegetates.', source: 'Musonius Rufus, Lecture 15' },
    { text: 'Never esteem anything as of advantage to you that will make you break your word or lose your self-respect.', source: 'Marcus Aurelius, Meditations 3.7' },
    { text: 'Be occupied not with the length of life but with its depth.', source: 'Seneca, Letters 49' },
    { text: 'What you do for others is the measure of what you do for yourself.', source: 'Marcus Aurelius, Meditations 6.6' },
    { text: 'He who acts justly injures no one. He who injures someone has not yet learned to act.', source: 'Marcus Aurelius, Meditations 9.1' },
    { text: 'Think it not among the last of your duties to reflect on whom you have helped today.', source: 'Seneca, Letters 2' },
    { text: 'What benefits do you give yourself? What benefits do you give to those around you?', source: 'Marcus Aurelius, Meditations 6.6' },
    { text: 'A person who refuses to help when they can has broken nature\'s law.', source: 'Marcus Aurelius, Meditations 9.1' },
    { text: 'First say to yourself what you would be; and then do what you have to do.', source: 'Epictetus, Discourses 3.23' },
    { text: 'We must love what fate assigns us and stop wishing it were otherwise. That is the key to great action.', source: 'Epictetus, Enchiridion 8' },
    { text: 'Look to others for your duty, to yourself for your character.', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'The only way to make sense out of change is to plunge into it, move with it, and join the dance.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Speak little. Do more. Let your actions be your words.', source: 'Marcus Aurelius, Meditations 10.1' },
    { text: 'One does not act bravely by denying danger. One acts bravely in spite of it.', source: 'Seneca, Letters 85' },
    { text: 'Concentrate every minute on doing what is in front of you with precise and genuine seriousness.', source: 'Marcus Aurelius, Meditations 4.26' },
    { text: 'The wise man is not surprised by anything. He has acted in such a way that nothing can overthrow him.', source: 'Seneca, Letters 76' },
    { text: 'When doing good, ask not whether it will be noticed. Ask only whether it was worth doing.', source: 'Marcus Aurelius, Meditations 9.42' },
    { text: 'How long will you wait before you demand the best of yourself?', source: 'Epictetus, Discourses 1.2' },
    { text: 'Act correctly once, and you will want to act correctly again. Action builds its own momentum.', source: 'Musonius Rufus' },
    { text: 'The measure of a man\'s virtue is what he does when no reward is offered.', source: 'Seneca, Letters 20' },
    { text: 'You have power over your actions and nothing else. Use that power fully.', source: 'Marcus Aurelius, Meditations 6.8' },
    { text: 'Pursue virtue, not profit. Pursue craft, not recognition.', source: 'Musonius Rufus, Lecture 4' },
    { text: 'Just because it can be done does not mean it should be done. Ask what truly needs doing.', source: 'Marcus Aurelius, Meditations 4.24' },
    { text: 'Work without attachment to results is true freedom of action.', source: 'Epictetus, Discourses 2.5' },
    { text: 'A task delayed by fear is never truly begun.', source: 'Seneca, Letters 3' },
    { text: 'The simplest things, done well and with full attention, are the foundation of the good life.', source: 'Musonius Rufus, Lecture 3' },
    { text: 'Think of yourself as both craftsman and work. You are shaping yourself with every action.', source: 'Epictetus, Discourses 1.15' },
    { text: 'Complete each day\'s task. Let tomorrow bring its own.', source: 'Marcus Aurelius, Meditations 7.8' },
    { text: 'If you do something that is hard and right, do not despise yourself if you tremble. That is courage.', source: 'Seneca, Letters 71' },
    { text: 'To act rightly, once, when everything is against you: that is the making of a character.', source: 'Marcus Aurelius, Meditations 9.16' },
    { text: 'Start from where you are. Use what you have. Do what you can.', source: 'Epictetus, Enchiridion 1 — adapted' },
    { text: 'To be always working, and always working usefully, requires more art than most men possess.', source: 'Seneca, Letters 72' },
    { text: 'Act in such a way that you could invite the world to watch.', source: 'Epictetus, Discourses 3.22' },
    { text: 'The first step of progress is refusing to be swept away by admiration of the wrong things.', source: 'Seneca, Letters 88' },
    { text: 'Do not be confused about what you are doing. Confusion in purpose creates confusion in action.', source: 'Marcus Aurelius, Meditations 4.2' },
    { text: 'What is the use of a good mind if it is applied to no useful work?', source: 'Seneca, Letters 82' },
    { text: 'Work is medicine for the anxious mind. Purposeful work is its cure.', source: 'Musonius Rufus, Lecture 5' },
    { text: 'Act once; reflect twice. The order matters.', source: 'Marcus Aurelius, Meditations 6.2' },
    { text: 'The man who does not act does not live. He merely waits.', source: 'Seneca, On the Shortness of Life 9' },
    { text: 'Doing less, but doing it well: that is the secret.', source: 'Marcus Aurelius, Meditations 4.24' },
    { text: 'The mind is the master of itself only when it has chosen and maintained its course under difficulties.', source: 'Seneca, Letters 71' },
    { text: 'For a man to conquer himself is the first and most noble of all victories.', source: 'Plato — approved by Stoics' },
    { text: 'This is the great discipline of life: to learn to want what actually happens.', source: 'Epictetus, Enchiridion 8' },
    { text: 'A ship is safe in harbour, but that is not what ships are for.', source: 'Seneca, Letters 83 — paraphrased' },
    { text: 'Carry out your tasks without boasting. Quietly, without praise, do what is required.', source: 'Marcus Aurelius, Meditations 10.1' },
    { text: 'Let every action aim at something real. Busy-ness without purpose exhausts the body and starves the soul.', source: 'Seneca, On the Shortness of Life 7' },
    { text: 'If you are pained by an external thing, it is not this thing that disturbs you, but your own judgment about it. You have the power to destroy that judgment now.', source: 'Marcus Aurelius, Meditations 8.47' },
    { text: 'One act of justice, done when justice is hard, is worth a lifetime of easy virtue.', source: 'Musonius Rufus, Lecture 2' },
    { text: 'The good sailor knows that storms cannot be avoided; they can only be navigated.', source: 'Seneca, Letters 85' },
    { text: 'We do not rise by wishing, but by acting — often poorly at first, then better.', source: 'Epictetus, Discourses 1.18' },
    { text: 'Complaining is not an action. It is a substitute for action.', source: 'Marcus Aurelius, Meditations 6.57' },
    { text: 'Courage is not the absence of fear but the action taken in spite of it.', source: 'Seneca, Letters 71' },
    { text: 'Whatever your work is, do it with your whole self. Half-hearted action is its own punishment.', source: 'Marcus Aurelius, Meditations 10.31' },
    { text: 'Act, then reflect on whether you acted rightly. Never stop examining.', source: 'Marcus Aurelius, Meditations 4.22' },
    { text: 'Character is what you do when no audience is watching.', source: 'Seneca, Letters 11' },
    { text: 'A fire may be smothered but never completely extinguished in the man of action.', source: 'Marcus Aurelius, Meditations 7.9' },
    { text: 'Do your duty today; tomorrow will ask the same of you, and you will be better equipped for it.', source: 'Marcus Aurelius, Meditations 2.5' },
    { text: 'The philosopher who does not act on his philosophy is merely a museum of ideas.', source: 'Epictetus, Discourses 3.21' },
    { text: 'Do not be troubled when something is hard. Be troubled only if you refuse to try.', source: 'Musonius Rufus, Lecture 7' },
    { text: 'What comes from within is never truly lost. Act from your inner resources, not from circumstances.', source: 'Marcus Aurelius, Meditations 11.11' },
    { text: 'Act justly, speak the truth, move with deliberate purpose. These three practices renew everything.', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'The life of action, lived virtuously, is the highest form of philosophy.', source: 'Musonius Rufus, Lecture 1' },
  ],

  assent: [
    { text: 'Never yield to the power of an impression. Say: wait, and I will see what you are, and what you represent.', source: 'Epictetus, Discourses 2.18' },
    { text: 'Things do not touch the soul. They stand outside it. Our disturbances come only from our inner view.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'An impression arrived. Let it wait outside. Do not let it in before you have examined it.', source: 'Epictetus, Discourses 2.18' },
    { text: 'If it is not right, do not do it; if it is not true, do not say it. And if it is not your own judgment, do not believe it.', source: 'Marcus Aurelius, Meditations 12.17' },
    { text: 'Man is not hurt by what happens to him, but by his opinion about what happens.', source: 'Epictetus, Enchiridion 5' },
    { text: 'Emotions are not facts. The first step toward wisdom is knowing which is which.', source: 'Marcus Aurelius, Meditations 6.8' },
    { text: 'You always have the option of having no opinion. If you don\'t know, say you don\'t know.', source: 'Marcus Aurelius, Meditations 6.52' },
    { text: 'The soul takes colour from thoughts. Dye it with thoughts of justice and common good.', source: 'Marcus Aurelius, Meditations 5.16' },
    { text: 'Ask yourself at every moment: is this impression necessary? Is it accurate? Is it mine?', source: 'Epictetus, Discourses 2.18' },
    { text: 'The beginning of philosophy is to know the condition of one\'s own mind.', source: 'Epictetus, Discourses 1.26' },
    { text: 'It is not the events that disturb the soul, but our response to events — and our response lives in us.', source: 'Seneca, Letters 104' },
    { text: 'Between stimulus and response, there is a space. That space is where freedom lives.', source: 'Marcus Aurelius, Meditations 6.8 — adapted' },
    { text: 'Never be satisfied with an impression at first appearance. Sleep on it. Test it.', source: 'Epictetus, Discourses 2.18' },
    { text: 'You cannot control the waves, but you can control the mind that watches them.', source: 'Epictetus, Enchiridion 1' },
    { text: 'The mark of the reasonable man is that he does not assent to what has not been proved.', source: 'Chrysippus — as reported by Sextus Empiricus' },
    { text: 'Every appearance presents itself as a candidate for belief. Not all candidates deserve election.', source: 'Epictetus, Discourses 1.20' },
    { text: 'Put every thought through this filter: is this true? Is it based on reality? Is it useful?', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'The untrained mind assents to everything. The trained mind assents to almost nothing without examination.', source: 'Epictetus, Discourses 3.8' },
    { text: 'Do not be carried away by an impression. Resist. Examine. Then, if it holds up, accept it.', source: 'Epictetus, Discourses 2.18' },
    { text: 'The greatest power a man possesses is the power to refuse agreement with false impressions.', source: 'Epictetus, Discourses 4.1' },
    { text: 'If you are pained by anything external, the pain is not from the thing, but from your own estimate of it — and this you have the power to revoke at any moment.', source: 'Marcus Aurelius, Meditations 8.47' },
    { text: 'Choose not to be harmed — and you won\'t feel harmed. Don\'t feel harmed — and you haven\'t been.', source: 'Marcus Aurelius, Meditations 4.7' },
    { text: 'It is absurd to carry the name of a philosopher and yet to behave in a way that is not philosophic.', source: 'Epictetus, Enchiridion 23' },
    { text: 'If a man\'s judgment is right, he has nothing to fear from the truth.', source: 'Marcus Aurelius, Meditations 9.27' },
    { text: 'How does what we call happiness differ from unhappiness, if only in the judgment we make of both?', source: 'Seneca, Letters 98' },
    { text: 'The very act of labelling something a disaster makes it one. Before labelling — pause.', source: 'Marcus Aurelius, Meditations 4.7' },
    { text: 'When we are offended by something, it is because we have already agreed that it matters too much.', source: 'Epictetus, Discourses 2.10' },
    { text: 'Do not spoil what you have by desiring what you have not, for what you already possess was once among the things you only hoped for.', source: 'Epicurus — quoted approvingly by Seneca' },
    { text: 'The problem is not the thing that happened. The problem is your interpretation of it.', source: 'Marcus Aurelius, Meditations 6.8' },
    { text: 'What is so-called evil is not in the world. It is in the mind that calls it so.', source: 'Epictetus, Discourses 2.1' },
    { text: 'The more accurately you see, the less you suffer. Suffering thrives in distortion.', source: 'Marcus Aurelius, Meditations 3.9' },
    { text: 'When something troubles you, ask: can I alter this? If no, then alter your judgment about it.', source: 'Marcus Aurelius, Meditations 7.9' },
    { text: 'You cannot control whether insults are thrown. You can control whether you pick them up.', source: 'Epictetus, Enchiridion 20 — paraphrased' },
    { text: 'What is contemptible is not poverty or pain; what is contemptible is choosing misery through faulty judgment.', source: 'Musonius Rufus, Lecture 2' },
    { text: 'The judgments you hold about yourself are more important than those held about you by others.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Label things correctly. Not \'I am ruined\' but \'I have lost something.\' Not \'this is terrible\' but \'this is difficult.\'', source: 'Epictetus, Discourses 3.19' },
    { text: 'Wisdom begins with the correct use of words. Call things what they actually are.', source: 'Marcus Aurelius, Meditations 6.13' },
    { text: 'When you call something a catastrophe, you have robbed yourself of the ability to respond to it clearly.', source: 'Seneca, Letters 13' },
    { text: 'A man who sees things as they truly are is disturbed by very little.', source: 'Marcus Aurelius, Meditations 9.13' },
    { text: 'The philosopher\'s chief instrument is the correct use of names and labels.', source: 'Epictetus, Discourses 1.17' },
    { text: 'When you lose your temper, you have lost something more precious than the argument.', source: 'Marcus Aurelius, Meditations 11.18' },
    { text: 'The pause between impulse and action is the cradle of all virtue.', source: 'Epictetus, Discourses 2.18' },
    { text: 'Anger begins in folly and ends in repentance. Do not let it begin.', source: 'Pythagoras — cited approvingly by Seneca' },
    { text: 'Count to ten. Count to a hundred. What remains when you have counted is the truth of the situation.', source: 'Seneca, On Anger 3.12' },
    { text: 'Everything is connected; but your reaction to everything is your own to govern.', source: 'Marcus Aurelius, Meditations 4.29' },
    { text: 'Do not be swept by first impressions. Look at things first from the outside, then from within.', source: 'Epictetus, Discourses 3.12' },
    { text: 'The mind untrained reacts. The mind trained responds. Train your mind.', source: 'Epictetus, Discourses 2.18' },
    { text: 'Grief, fear, and anxiety are failures of judgment. They arise from assenting to false impressions.', source: 'Chrysippus — as reported by Stobaeus' },
    { text: 'The man who cannot stop himself from reacting has surrendered his freedom to the first person who provokes him.', source: 'Epictetus, Discourses 4.1' },
    { text: 'Pause. Breathe. Ask: what is actually happening here, stripped of my story about it?', source: 'Marcus Aurelius, Meditations 8.47' },
    { text: 'When you feel anger rising, say to yourself: anger is a choice. I am choosing not to make it.', source: 'Seneca, On Anger 3.1' },
    { text: 'The man easily moved by appearances is like a rudderless ship — pushed wherever the wind blows.', source: 'Epictetus, Discourses 2.15' },
    { text: 'React less. Reflect more. Then choose your response.', source: 'Marcus Aurelius, Meditations 6.26' },
    { text: 'Bad things appear worse than they are when we meet them unprepared. Keep the mind always ready.', source: 'Seneca, Letters 98' },
    { text: 'Do not seek revenge when wronged. Seek only to correct your own judgment about what has happened.', source: 'Marcus Aurelius, Meditations 6.6' },
    { text: 'The fastest way to be calm is to refuse to agree that the situation is an emergency.', source: 'Epictetus, Enchiridion 20' },
    { text: 'Nothing is an emergency until you decide it is. Most things are merely inconveniences.', source: 'Marcus Aurelius, Meditations 6.52' },
    { text: 'You give power to what you pay attention to. Pay attention wisely.', source: 'Epictetus, Discourses 4.1' },
    { text: 'The angry man is at war with himself. The serene man is at peace with the world.', source: 'Seneca, On Anger 1.1' },
    { text: 'If you meet rudeness with rudeness, you have doubled the disorder in the world.', source: 'Marcus Aurelius, Meditations 11.18' },
    { text: 'We fear our own shadows. Most of what we dread never arrives; most of what arrives we can bear.', source: 'Seneca, Letters 13' },
    { text: 'What is praised by the crowd is mostly not worth having. What is feared by the crowd is mostly not worth fearing.', source: 'Marcus Aurelius, Meditations 6.16' },
    { text: 'The mob\'s applause is no confirmation of worth. Neither is the mob\'s contempt a sign of failure.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Fame is the shadow of virtue. Chase the shadow and you lose the substance.', source: 'Seneca, Letters 79' },
    { text: 'Many are harmed by glory; many by money; few by what they truly are.', source: 'Seneca, Letters 87' },
    { text: 'The mind that follows the crowd can never be its own master.', source: 'Marcus Aurelius, Meditations 7.62' },
    { text: 'The worst poverty is the poverty of an uncritical mind that accepts everything it is told.', source: 'Epictetus, Discourses 2.1' },
    { text: 'Luxury is not comfort; it is the fear of discomfort dressed up as pleasure.', source: 'Musonius Rufus, Lecture 20' },
    { text: 'To be rich beyond your needs is merely to have exchanged one set of worries for another.', source: 'Seneca, Letters 17' },
    { text: 'Most men\'s pleasures are made of borrowed cloth: borrowed from society, from ambition, from fear of boredom.', source: 'Seneca, Letters 8' },
    { text: 'What the many believe is mostly what they have been told to believe. Examine your beliefs rigorously.', source: 'Epictetus, Discourses 2.11' },
    { text: 'The opinion of others is not a mirror; it is a hall of distorting mirrors.', source: 'Marcus Aurelius, Meditations 12.4' },
    { text: 'Real wealth is measured inwardly. External measures of wealth are always at the mercy of external forces.', source: 'Seneca, Letters 77' },
    { text: 'What is it that you fear losing? Now ask whether the loss of that would make you less virtuous.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'A man who can be bought has no true convictions. A man with true convictions cannot be bought.', source: 'Epictetus, Discourses 4.1' },
    { text: 'Never accept the crowd\'s verdict on what is good and what is evil without investigation.', source: 'Seneca, Letters 29' },
    { text: 'The phantom good is worse than no good at all, because it deceives and distracts from the real.', source: 'Chrysippus — as reported by Plutarch' },
    { text: 'Do not let the noise of others\' opinions drown out your own inner voice.', source: 'Epictetus, Enchiridion 1' },
    { text: 'The man who always wants to be comfortable will never be truly alive.', source: 'Musonius Rufus, Lecture 7' },
    { text: 'Appearances deceive. They show us the mask, not the face. Look deeper.', source: 'Marcus Aurelius, Meditations 9.29' },
    { text: 'If you could say, at the end of any day, that you saw things clearly today — that is a day well lived.', source: 'Marcus Aurelius, Meditations 10.11' },
    { text: 'The healthy eye can look at all colours — even yellow — without complaint. So too the healthy mind.', source: 'Marcus Aurelius, Meditations 10.35' },
    { text: 'The greatest gift one can give oneself is a mind trained to see things as they are.', source: 'Epictetus, Discourses 1.1' },
    { text: 'Reality is not good or bad; it is only our responses that can be called good or bad.', source: 'Marcus Aurelius, Meditations 6.52' },
    { text: 'A mind that is always somewhere else is never anywhere. Bring it here, to this moment.', source: 'Marcus Aurelius, Meditations 8.7' },
    { text: 'Separate opinion from fact. Fact is stubborn. Opinion is flexible. Know which is which.', source: 'Marcus Aurelius, Meditations 6.13' },
    { text: 'A clear mind is not the absence of thought, but the absence of untested thought.', source: 'Epictetus, Discourses 2.18' },
    { text: 'The wise man does not argue with reality. He simply sees it for what it is.', source: 'Marcus Aurelius, Meditations 9.13' },
    { text: 'Truth is not always pleasant. But the man who insists on pleasant truths will live among lies.', source: 'Seneca, Letters 29' },
    { text: 'If you cannot think clearly, you cannot live clearly. Clear thinking is the precondition of the good life.', source: 'Epictetus, Discourses 1.17' },
    { text: 'When you see a thing as it actually is — stripped of imagination, fear, and vanity — it is usually much smaller than you thought.', source: 'Marcus Aurelius, Meditations 9.36' },
    { text: 'Hold every impression lightly until you have examined it. Then either adopt it or let it go.', source: 'Epictetus, Discourses 2.18' },
    { text: 'A lie believed is more dangerous than a truth ignored, because you will act on the lie.', source: 'Marcus Aurelius, Meditations 12.24' },
    { text: 'The mark of an educated mind is to be able to entertain a thought without accepting it.', source: 'Aristotle — cited approvingly in Stoic schools' },
    { text: 'See things first with a beginner\'s mind, before your habits of judgment take over.', source: 'Epictetus, Discourses 1.26' },
    { text: 'Look at everything you do with fresh eyes. What are you actually doing, stripped of all narrative?', source: 'Marcus Aurelius, Meditations 9.29' },
    { text: 'Not every thought that passes through the mind deserves to stay there. Evict those that serve no good.', source: 'Marcus Aurelius, Meditations 5.16' },
    { text: 'The quiet mind is not empty. It is full of clear seeing, undistorted by fear or desire.', source: 'Epictetus, Discourses 3.15' },
    { text: 'Your judgments either make you free or imprison you. Choose them with the same care you\'d choose a companion.', source: 'Epictetus, Discourses 4.1' },
    { text: 'What you attend to, you become. Attend to the true, the good, and the beautiful.', source: 'Marcus Aurelius, Meditations 4.2' },
    { text: 'At the centre of yourself there is the ruling faculty — the part that decides. Defend it above all things.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Your mind, when uncorrupted, is the only true sanctuary.', source: 'Marcus Aurelius, Meditations 8.48' },
    { text: 'Protect your mind from the assault of wrong opinions as you would protect your body from disease.', source: 'Epictetus, Discourses 3.22' },
    { text: 'The intellect is the man. Govern it well.', source: 'Marcus Aurelius, Meditations 12.3' },
    { text: 'Teach yourself to live without anything that disturbs your mind\'s equilibrium.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'You do not need the outside world to be perfect in order for your mind to be at peace.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'The commanding faculty is like a fire: it can warm the house or burn it down, depending on whose hands control it.', source: 'Seneca, Letters 66' },
    { text: 'Govern your thoughts before they govern you.', source: 'Marcus Aurelius, Meditations 9.7' },
    { text: 'The body is the vehicle. The mind is the driver. Keep the driver sober.', source: 'Musonius Rufus, Lecture 6' },
    { text: 'When the mind is clear, the body follows. When the mind is disordered, nothing goes right.', source: 'Seneca, Letters 78' },
    { text: 'Return again and again to your own mind: it alone is your country.', source: 'Marcus Aurelius, Meditations 4.3' },
    { text: 'Philosophy\'s highest achievement is to leave the mind undisturbed in the face of what disturbs others.', source: 'Seneca, Letters 66' },
    { text: 'The man who controls his mind controls his life. All external victories are secondary to this one.', source: 'Epictetus, Discourses 4.1' },
    { text: 'The mind is its own place. Make it a good one.', source: 'Marcus Aurelius, Meditations 8.48' },
    { text: 'A mind that examines its own workings is always sharper than one that only examines the world.', source: 'Epictetus, Discourses 1.26' },
    { text: 'To know how to refuse bad thoughts is as important as knowing how to form good ones.', source: 'Marcus Aurelius, Meditations 5.16' },
    { text: 'Think of the mind as a muscle: what you exercise in it grows, what you neglect in it weakens.', source: 'Musonius Rufus, Lecture 6' },
    { text: 'If the mind is not enslaved to impressions, nothing outside it can enslave it.', source: 'Epictetus, Discourses 1.1' },
    { text: 'The seat of all virtue is in the mind. That is also the seat of all corruption. Guard it accordingly.', source: 'Marcus Aurelius, Meditations 6.8' },
    { text: 'A mind trained in assent is a mind that can be trusted. All other training is preparation for this.', source: 'Epictetus, Discourses 2.18' },
    { text: 'What corrupts the mind? Yielding to false impressions. What purifies it? Refusing to yield.', source: 'Epictetus, Discourses 3.3' },
    { text: 'The most powerful force in the universe is a human mind that sees clearly and acts accordingly.', source: 'Marcus Aurelius, Meditations 12.23' },
  ],

};

